/**
 * Find stale subscriptions (no updates in 7 days)
 */
registerCronJob('reminder:subscription:stale', {
  interval: '1d',
  description: 'Find subscriptions with no activity for 7 days',
  handler: async () => {
    const { rows: tenants } = await pool.query(
      'SELECT DISTINCT tenant_id FROM users WHERE is_active = true AND deleted_at IS NULL'
    );
    const allRows = [];
    for (const { tenant_id } of tenants) {
      const { rows } = await pool.query(
        `SELECT id, status, updated_at FROM subscriptions
         WHERE updated_at < NOW() - INTERVAL '7 days'
         AND tenant_id = $1 AND deleted_at IS NULL
         AND status NOT IN ('cancelled')
         LIMIT 100`,
        [tenant_id]
      );
      allRows.push(...rows);
    }
    const rows = allRows;
    if (rows.length > 0) {
      console.log('⚠️  ' + rows.length + ' stale subscription(s) found');
    }
    return { stale: rows.length };
  },
});

